#include <stdio.h>
#define DIM 5

int main() {
    int i, j, kolona1, kolona2, temp;
    int matrica[DIM][DIM] = {
        {1, 2, 3, 4, 5},
        {6, 7, 8, 9, 9},
        {8, 7, 6, 5, 4},
        {3, 2, 1, 1, 2},
        {3, 4, 5, 6, 7}
    };

    printf("Unesite indekse kolona koje zelite zamijeniti (0-%d): \n", DIM - 1);
    scanf("%d %d", &kolona1, &kolona2);
    
    if (kolona1 < 0 || kolona1 >= DIM || kolona2 < 0 || kolona2 >= DIM || kolona1 == kolona2) {
        printf("Nevalidan unos!");
        return 1;
    }

    /* Zamjena kolona */
    for (i = 0; i < DIM; i++) {
        temp = matrica[i][kolona1];
        matrica[i][kolona1] = matrica[i][kolona2];
        matrica[i][kolona2] = temp;
    }

    printf("Matrica nakon zamjene kolona %d i %d:\n", kolona1, kolona2);
    for (i = 0; i < DIM; i++) {
        for (j = 0; j < DIM; j++) {
            printf("%d ", matrica[i][j]);
        }
        printf("\n");
    }

    return 0;
}
